const { InfluxDB, Point } = require('@influxdata/influxdb-client');
const { BucketsAPI, OrgsAPI } = require('@influxdata/influxdb-client-apis');

// InfluxDB configuration with authentication
const token = process.env.INFLUXDB_TOKEN; // Store in Azure Key Vault
const org = 'my-org';
const bucket = 'financial-metrics';
const url = 'https://influxdb.example.com';

const influxDB = new InfluxDB({ url, token });
const writeApi = influxDB.getWriteApi(org, bucket, 'ns', {
  // Write options with batching
  batchSize: 1000,
  flushInterval: 10000,
  maxRetries: 3,
  maxRetryDelay: 15000,
});

// Configure retention policy (server-side enforcement)
const bucketsAPI = new BucketsAPI(influxDB);

async function configureRetentionPolicy() {
  const orgsAPI = new OrgsAPI(influxDB);
  const organizations = await orgsAPI.getOrgs({ org });
  const orgID = organizations.orgs[0].id;

  // Create bucket with 30-day retention
  const bucketConfig = {
    orgID,
    name: bucket,
    retentionRules: [
      {
        type: 'expire',
        everySeconds: 30 * 24 * 60 * 60, // 30 days
        shardGroupDurationSeconds: 7 * 24 * 60 * 60, // 7 days
      },
    ],
  };

  try {
    await bucketsAPI.postBuckets({ body: bucketConfig });
    console.log('Retention policy configured: 30-day auto-deletion');
  } catch (error) {
    console.error('Bucket already exists or error:', error);
  }
}

// Secure write function with timestamp validation
function writeMetric(measurement, tags, fields, timestamp = null) {
  const point = new Point(measurement);

  // Validate timestamp is within acceptable drift (±5 minutes)
  const now = Date.now();
  const providedTimestamp = timestamp || now;
  const maxDrift = 5 * 60 * 1000; // 5 minutes in ms

  if (Math.abs(now - providedTimestamp) > maxDrift) {
    throw new Error(
      `Timestamp drift exceeds limit: ${Math.abs(now - providedTimestamp)}ms > ${maxDrift}ms. ` +
      `Possible backdating attack detected.`
    );
  }

  // Add tags (validated against whitelist)
  const allowedTags = ['region', 'environment', 'host', 'service'];
  for (const [key, value] of Object.entries(tags)) {
    if (!allowedTags.includes(key)) {
      throw new Error(`Invalid tag: ${key}. Allowed: ${allowedTags.join(', ')}`);
    }
    // Sanitize tag values to prevent injection
    const sanitizedValue = String(value).replace(/[^a-zA-Z0-9-_]/g, '');
    point.tag(key, sanitizedValue);
  }

  // Add fields (type validation)
  for (const [key, value] of Object.entries(fields)) {
    if (typeof value === 'number') {
      // Validate numeric range for financial metrics
      if (measurement === 'stock_price' && (value < 0 || value > 1000000)) {
        throw new Error(`Invalid stock price: ${value}. Must be 0-1000000.`);
      }
      point.floatField(key, value);
    } else if (typeof value === 'string') {
      point.stringField(key, value);
    } else if (typeof value === 'boolean') {
      point.booleanField(key, value);
    } else {
      throw new Error(`Unsupported field type for ${key}: ${typeof value}`);
    }
  }

  // Use validated timestamp (server time if drift detected)
  point.timestamp(providedTimestamp);

  writeApi.writePoint(point);
}

// Example: Write stock trade metric with validation
try {
  writeMetric(
    'stock_trades',
    { region: 'us-east', environment: 'prod' },
    { price: 145.32, volume: 10000 },
    Date.now() // Use current timestamp
  );

  // This would fail timestamp validation (backdating)
  // writeMetric(
  //   'stock_trades',
  //   { region: 'us-east', environment: 'prod' },
  //   { price: 999.99, volume: 50000 },
  //   Date.now() - 60 * 24 * 60 * 60 * 1000 // 60 days ago - REJECTED
  // );

  await writeApi.close();
  console.log('Metrics written successfully');
} catch (error) {
  console.error('Write failed:', error.message);
  await writeApi.close();
}

// Initialize retention policy on startup
configureRetentionPolicy();

