// AZURE SENTINEL (KQL) - Detect InfluxDB Timestamp Backdating
// ========================================
let timeWindow = 1h;
let maxDrift = 5m;
InfluxDBLogs
| where TimeGenerated > ago(timeWindow)
| where EventType == "write"
| extend TimestampDrift = abs(datetime_diff('second', EventTimestamp, ingestion_time()))
| where TimestampDrift > totalseconds(maxDrift)
| summarize 
    BackdatedWrites = count(),
    MaxDrift = max(TimestampDrift),
    AvgDrift = avg(TimestampDrift),
    TargetBuckets = make_set(Bucket)
    by SourceIP, UserIdentity, bin(TimeGenerated, 5m)
| where BackdatedWrites > 10
| extend Severity = case(
    MaxDrift > 86400, "Critical", // >1 day drift
    MaxDrift > 3600, "High",       // >1 hour drift
    "Medium"
  )
| project 
    TimeGenerated,
    SourceIP,
    UserIdentity,
    BackdatedWrites,
    MaxDriftHours = MaxDrift / 3600.0,
    TargetBuckets,
    Severity
| order by MaxDriftHours desc

// AZURE SENTINEL - Detect Metric Injection Anomalies
let baselineWindow = 7d;
let detectionWindow = 1h;
PrometheusMetrics
| where TimeGenerated > ago(baselineWindow)
| where MetricName == "http_requests_total"
| summarize 
    BaselineRate = avg(Rate),
    BaselineStdDev = stdev(Rate)
    by Job, Instance
| join kind=inner (
    PrometheusMetrics
    | where TimeGenerated > ago(detectionWindow)
    | where MetricName == "http_requests_total"
    | summarize CurrentRate = avg(Rate) by Job, Instance
  ) on Job, Instance
| extend ZScore = (CurrentRate - BaselineRate) / BaselineStdDev
| where ZScore > 10 // 10 standard deviations = likely injection
| project 
    Job,
    Instance,
    BaselineRate,
    CurrentRate,
    PercentIncrease = ((CurrentRate - BaselineRate) / BaselineRate) * 100,
    ZScore,
    Severity = "High"
| order by ZScore desc

