// ELASTIC STACK (EQL) - Detect TimescaleDB RLS Bypass Attempts
// ========================================
sequence by user.name, source.ip with maxspan=10m
  [authentication where event.outcome == "success" and user.roles: "sensor_writer"]
  [database where 
    event.action in ("UPDATE", "DELETE") and 
    database.name == "iot_sensors" and 
    database.table == "sensor_readings" and 
    event.outcome == "failure" and 
    error.message: "*row-level security policy*"
  ]
| stats count = count() by user.name, source.ip
| where count > 5

