// ========================================
// SPLUNK (SPL) - Detect Prometheus Remote Write Authentication Failures
// ========================================
index=prometheus_logs sourcetype=thanos_receive
| where status IN (401, 403) AND request_path="/api/v1/receive"
| eval hour=strftime(_time, "%Y-%m-%d %H:00")
| stats 
    count as FailedWrites,
    dc(src_ip) as UniqueSources,
    values(user_agent) as UserAgents,
    values(tls_error) as TLSErrors
    by hour, src_ip
| where FailedWrites > 20
| eval Severity=case(
    FailedWrites > 100, "Critical",
    FailedWrites > 50, "High",
    1=1, "Medium"
  )
| table hour, src_ip, FailedWrites, UniqueSources, UserAgents, TLSErrors, Severity
| sort -FailedWrites

// SPLUNK - Detect Continuous Query Exploitation
index=influxdb_logs sourcetype=influxdb_query
| where query_type="continuous_query"
| rex field=query "INTO (?<target_measurement>[^\s]+)"
| stats 
    count as ExecutionCount,
    values(query) as Queries,
    dc(target_measurement) as UniqueMeasurements
    by user, src_ip, _time
| where UniqueMeasurements > 10 OR ExecutionCount > 100
| eval Severity="High"
| table _time, user, src_ip, ExecutionCount, UniqueMeasurements, Severity

// ========================================
// AWS CLOUDWATCH INSIGHTS - Detect IoT Metric Tampering
// ========================================
fields @timestamp, source_ip, sensor_id, temperature, timestamp_drift
| filter event_type = "sensor_write"
| filter timestamp_drift > 300 OR temperature > 100 OR temperature < -50
| stats 
    count(*) as SuspiciousWrites,
    max(timestamp_drift) as MaxDriftSeconds,
    avg(temperature) as AvgTemperature,
    count_distinct(sensor_id) as UniqueSensors
    by source_ip, bin(5m)
| filter SuspiciousWrites > 5
| sort MaxDriftSeconds desc

// CLOUDWATCH INSIGHTS - Detect Financial Metric Manipulation
fields @timestamp, user_id, metric_name, old_value, new_value, operation
| filter metric_name in ["stock_price", "trade_volume", "account_balance"]
| filter operation in ["UPDATE", "DELETE"]
| parse @message /user=(?<user_id>\w+).*old=(?<old_value>[\d.]+).*new=(?<new_value>[\d.]+)/
| stats 
    count(*) as ModificationCount,
    sum(abs(new_value - old_value)) as TotalDelta
    by user_id, metric_name, bin(1h)
| filter ModificationCount > 10 OR TotalDelta > 100000
| sort TotalDelta desc
